def query_rag(question):
    client = openai.OpenAI(api_key=st.secrets["OPENAI_API_KEY"])
    context = "\n\n".join([
        f"[Article {a['id']}] {a['tag']} | {a['title']} | {a['date']}\n{a['content']}"
        for a in ARTICLES
    ])
    response = client.chat.completions.create(
        model="gpt-4o-mini",
        max_tokens=500,
        messages=[
            {"role": "system", "content": "You are ET Intelligence, a financial news assistant powered by The Economic Times archive. Answer using ONLY the provided articles. Be concise and analytical for BFSI professionals. End with SOURCES: followed by article titles used."},
            {"role": "user", "content": f"Articles:\n{context}\n\nQuestion: {question}"}
        ]
    )
    full = response.choices[0].message.content
    if "SOURCES:" in full:
        parts = full.split("SOURCES:")
        answer = parts[0].strip()
        sources = [s.strip("•-– ").strip() for s in parts[1].strip().split("\n") if s.strip()]
    else:
        answer = full
        sources = ["Economic Times archive"]
    return {"answer": answer, "sources": sources}

def show_signup():
    col_left, col_right = st.columns([2, 3])
    with col_left:
        st.markdown(f"""
        <div class="auth-left">
            <div style="text-align:center">
                <img src="data:image/jpeg;base64,{ET_LOGO}"
                     style="width:140px;border-radius:8px;margin-bottom:14px;" />
                <div class="auth-tagline">Powered by BCCL · Times Group</div>
            </div>
            <div class="auth-quote">"180 years of journalism, structured for the decisions you make today."</div>
            <div class="auth-meta">Enterprise Access · BFSI Edition</div>
        </div>""", unsafe_allow_html=True)
    with col_right:
        st.markdown("### Create your account")
        st.caption("Get access to ET Intelligence — the enterprise news platform")
        c1, c2 = st.columns(2)
        with c1: fname = st.text_input("First name", placeholder="Rahul")
        with c2: lname = st.text_input("Last name", placeholder="Sharma")
        email = st.text_input("Work email", placeholder="rahul@hdfcbank.com")
        org = st.text_input("Organisation", placeholder="HDFC Bank")
        desig = st.selectbox("Your designation", DESIGNATIONS)
        password = st.text_input("Password", type="password", placeholder="Min 8 characters")
        if st.button("Create account & get access", use_container_width=True, type="primary"):
            if not all([fname, lname, email, org, password]) or len(password) < 8:
                st.error("Please fill all fields. Password must be at least 8 characters.")
            elif email in st.session_state.users_db:
                st.error("Email already registered. Please sign in.")
            else:
                st.session_state.users_db[email] = {
                    "password": hashlib.md5(password.encode()).hexdigest(),
                    "name": f"{fname} {lname}", "org": org, "desig": desig
                }
                st.session_state.current_user = {"name": f"{fname} {lname}", "org": org, "desig": desig}
                st.session_state.logged_in = True
                st.rerun()
        st.markdown("---")
        if st.button("Already have an account? Sign in"):
            st.session_state.auth_mode = "login"
            st.rerun()

